using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class ModelMetrics
{
    public double MicroAccuracy { get; set; }
    public double MacroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public string ConfusionMatrix { get; set; } = string.Empty;
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;
    private ModelMetrics? _metrics;

    public ModelMetrics? Metrics => _metrics;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with {Path}", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _metrics = new ModelMetrics
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            ConfusionMatrix = metrics.ConfusionMatrix.GetFormattedConfusionTable()
        };

        _logger.LogInformation("MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        // Retrain on full dataset for production model
        var fullModel = pipeline.Fit(data);
        _mlContext.Model.Save(fullModel, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;

    public TicketController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var labels = new[] { "Billing", "General", "Technical" };
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpGet("metrics")]
    public ActionResult<ModelMetrics> GetMetrics()
    {
        var metrics = _trainingService.Metrics;
        if (metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(metrics);
    }
}

